from dataclasses import dataclass, field
from typing import Optional
from enum import Enum

class RequirementType(str, Enum):
    FUNCTIONAL   = "functional"
    NON_FUNCTIONAL = "non_functional"
    CONSTRAINT   = "constraint"

class FindingSeverity(str, Enum):
    HIGH   = "high"    # blocks adoption or causes regulatory/quality risk
    MEDIUM = "medium"  # degrades experience; recoverable
    LOW    = "low"     # friction; nice to address

@dataclass
class ResearchFinding:
    finding_id: str
    phase: str                    # interview phase or method that surfaced it
    verbatim: str                 # exact quote or close paraphrase
    participant_ids: list[str]    # who said it
    frequency: str                # "5 of 6 participants", "every session"
    severity: FindingSeverity
    finding_type: str             # "pain_point", "trust_threshold", "expectation", "constraint"
    researcher_insight: Optional[str] = None   # synthesis / so-what (labelled as inference)

@dataclass
class DerivedRequirement:
    req_id: str
    req_type: RequirementType
    statement: str
    source_finding_id: str        # traceable back to ResearchFinding
    verbatim_evidence: str        # the quote that justifies this requirement
    owner: str
    acceptance_criteria: list[str] = field(default_factory=list)
    eval_gate: Optional[str] = None   # linked eval set criterion if measurable

@dataclass
class ResearchHandoff:
    feature_name: str
    findings: list[ResearchFinding] = field(default_factory=list)
    requirements: list[DerivedRequirement] = field(default_factory=list)

    def untraceable_requirements(self) -> list[DerivedRequirement]:
        finding_ids = {f.finding_id for f in self.findings}
        return [r for r in self.requirements if r.source_finding_id not in finding_ids]

    def high_severity_without_requirement(self) -> list[ResearchFinding]:
        req_sources = {r.source_finding_id for r in self.requirements}
        return [
            f for f in self.findings
            if f.severity == FindingSeverity.HIGH and f.finding_id not in req_sources
        ]

    def validate(self) -> list[str]:
        errors = []
        errors.extend(
            f"Requirement '{r.req_id}' has no traceable finding"
            for r in self.untraceable_requirements()
        )
        errors.extend(
            f"High-severity finding '{f.finding_id}' has no derived requirement"
            for f in self.high_severity_without_requirement()
        )
        return errors

# Research handoff meeting: agenda and artefact checklist

HANDOFF_AGENDA = {
    "attendees": [
        "Product Manager (owns requirements doc)",
        "Lead Engineer (technical feasibility check)",
        "AI Quality Researcher (eval harness ownership)",
        "Delivery Manager (prioritisation)",
        "UX Designer (interaction design implications)",
    ],
    "duration": "90 minutes",
    "sections": [
        {
            "title": "1. Research summary (15 min)",
            "content": [
                "Methods used: interviews (n=6), error injection study (n=12), expectation survey (n=40)",
                "Top 5 findings with frequency and severity",
                "Key trust calibration result: automation bias rate on critical errors",
            ],
        },
        {
            "title": "2. Finding-to-requirement walkthrough (30 min)",
            "content": [
                "Walk through each high-severity finding",
                "Present derived requirement alongside verbatim evidence",
                "Discuss: is the requirement correctly scoped? Is the owner correct?",
                "Flag any requirement that could not be traced to a finding",
            ],
        },
        {
            "title": "3. Constraint and guardrail review (20 min)",
            "content": [
                "Review all constraint requirements derived from Phase 3 (trust threshold findings)",
                "Confirm AI scope boundaries with engineering lead",
                "Agree escalation trigger requirements",
            ],
        },
        {
            "title": "4. NFR and acceptance criteria review (15 min)",
            "content": [
                "Review quantitative NFRs derived from expectation survey and error injection study",
                "Confirm eval gate configuration for each accuracy NFR",
                "Identify NFRs without an acceptance criterion — assign owner to complete",
            ],
        },
        {
            "title": "5. Open questions and follow-up (10 min)",
            "content": [
                "Findings with insufficient evidence (1 participant only) — flag as hypothesis",
                "Out-of-scope opportunities discovered — log in backlog",
                "Wave 2 research triggers: what questions must the pilot answer?",
            ],
        },
    ],
}

# Pre-meeting artefact checklist
HANDOFF_ARTEFACTS = {
    "findings_doc": "All findings with verbatim, frequency, severity, and participant IDs",
    "insight_doc":  "Researcher synthesis — labelled as inference, not raw data",
    "requirements_draft": "FR / NFR / CONST for each HIGH severity finding",
    "acceptance_criteria_draft": "Gherkin-style ACs for each requirement",
    "open_questions_log": "Unanswered questions to carry into Wave 2 research or pilot",
    "out_of_scope_log":   "Opportunities discovered but not in current scope",
}
